mapper.select:
SELECT 
FROM workspace_member
WHERE workspace_id = #{workspaceId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND user_id = #{userId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

SELECT 
FROM workspace_member
WHERE workspace_id = #{workspaceId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

    AND organization_id = #{organizationId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


    AND EXISTS (
        SELECT 1 FROM workspace_member_role wmr
        WHERE wmr.member_id = workspace_member.id
          AND wmr.role_id = #{roleId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
    )


    AND status = #{status, typeHandler=com.pdp.persistence.typehandler.StringEnumTypeHandler}


    AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

ORDER BY id ASC
LIMIT #{size}

mapper.update:
UPDATE workspace_member
SET status = #{newStatus, typeHandler=com.pdp.persistence.typehandler.StringEnumTypeHandler},
    updated_at = #{now, typeHandler=com.pdp.persistence.typehandler.InstantTypeHandler},
    revision = revision + 1
WHERE id = #{id, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND revision = #{expectedRevision}
